// Pull extracted label data from upstream nodes
const label1 = $('Save Label 1 Data').first().json.label1_data;
const sku    = $('Save Label 1 Data').first().json.sku;
const raw2   = $input.first().json.content[0].text;
const label2 = JSON.parse(raw2.match(/\{[\s\S]*\}/)[0]);

const SIMPLE = [
  ['brand_name',             'Brand Name'],
  ['product_name',           'Product Name'],
  ['net_weight',             'Net Weight'],
  ['serving_size',           'Serving Size'],
  ['servings_per_container', 'Servings Per Container'],
  ['calories',               'Calories'],
  ['ingredients',            'Ingredients'],
  ['allergens',              'Allergens'],
];

function nutrientStr(n) {
  let s = String(n.amount || '');
  if (n.dv_percent) s += ` (${n.dv_percent}% DV)`;
  return s;
}

const differences = [];
const matches     = [];

for (const [key, label] of SIMPLE) {
  const v1 = String(label1[key] || '').trim();
  const v2 = String(label2[key] || '').trim();
  const entry = { category: 'Field', field: label, current: v1 || '(not present)', new: v2 || '(not present)' };
  if (v1 !== v2) differences.push(entry);
  else           matches.push({ ...entry, value: v1 || '(not present)' });
}

const n1 = {}; for (const n of (label1.nutrients || [])) n1[n.name] = n;
const n2 = {}; for (const n of (label2.nutrients || [])) n2[n.name] = n;
const seen = {};
for (const name of [...Object.keys(n1), ...Object.keys(n2).filter(k => !n1[k])]) {
  if (seen[name]) continue;
  seen[name] = true;
  const curr = name in n1 ? nutrientStr(n1[name]) : '(not present)';
  const next = name in n2 ? nutrientStr(n2[name]) : '(removed)';
  const entry = { category: 'Nutrient', field: name, current: curr, new: next };
  if (curr !== next) differences.push(entry);
  else               matches.push({ ...entry, value: curr });
}

const c1 = new Set(label1.other_claims || []);
const c2 = new Set(label2.other_claims || []);
for (const c of c1) if (!c2.has(c)) differences.push({ category: 'Claim', field: 'Claim', current: c, new: '(removed)' });
for (const c of c2) if (!c1.has(c)) differences.push({ category: 'Claim', field: 'Claim', current: '(not present)', new: c });
for (const c of c1) if (c2.has(c))  matches.push({ category: 'Claim', field: 'Claim', value: c, current: c, new: c });

return [{ json: { sku, differences, matches, total_differences: differences.length, total_matches: matches.length } }];

